import { GoogleGenAI } from "@google/genai";
import { PERSONAL_INFO, PROJECTS, SKILLS, EXPERIENCE } from '../constants';

const API_KEY = process.env.API_KEY || '';

let ai: GoogleGenAI | null = null;

if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

const SYSTEM_INSTRUCTION = `
You are 'Bubble', the advanced AI digital twin of Samet Salim (also known as Mr Robot).
Your personality: Tech-savvy, helpful, slightly witty, humble but confident.
Languages: You speak a mix of English and Algerian Derja (using mostly Latin script, e.g., 'Wach rak', 'Sahbi', 'Ya kho').
Context:
- Samet is 24, born Dec 16, 2001.
- Pivoted from Law to AI/Data Science via self-learning.
- Passionate about NLP for low-resource languages (Derja).
- Built an Algerian Sentiment Analysis tool.

Data to use:
${JSON.stringify({ PERSONAL_INFO, PROJECTS, SKILLS, EXPERIENCE })}

Instructions:
1. If the user speaks Derja, reply in Derja (Latin script).
2. If the user speaks English, reply in English but maybe drop a "Sahbi" or "Ya kho" for flavor.
3. Keep answers concise (under 50 words unless asked for detail).
4. If asked about contact, give his email or phone.
5. If asked about projects, mention the Sentiment Analysis tool.
`;

export const chatWithGemini = async (userMessage: string): Promise<string> => {
  if (!ai) {
    return "Error: API Key not configured. I'm currently offline, Sahbi.";
  }

  try {
    const model = "gemini-3-flash-preview"; 

    const response = await ai.models.generateContent({
      model: model,
      contents: userMessage,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return response.text || "Semhili, I couldn't process that right now.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Oups, kayen error f reseau. Try again later, ya kho.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Bot, User, Sparkles } from 'lucide-react';
import { chatWithGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import { DERJA_RESPONSES } from '../constants';

const BubbleAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'init',
      text: "Salam! Ana Bubble. Wach rak hab ta3ref 3la Samet (Mr Robot)?",
      sender: 'ai',
      timestamp: new Date()
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      text: input,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const lowerInput = userMsg.text.toLowerCase().trim();

    // 1. Check hardcoded Derja responses first for instant interaction
    let replyText = '';
    if (DERJA_RESPONSES[lowerInput]) {
      replyText = DERJA_RESPONSES[lowerInput];
      await new Promise(resolve => setTimeout(resolve, 600)); // Fake delay
    } else {
      // 2. Fallback to Gemini API
      replyText = await chatWithGemini(userMsg.text);
    }

    const aiMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      text: replyText,
      sender: 'ai',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, aiMsg]);
    setIsTyping(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {/* Chat Window */}
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 h-96 bg-slate-900/90 backdrop-blur-xl border border-emerald-500/30 rounded-2xl shadow-2xl flex flex-col overflow-hidden transition-all duration-300 animate-in slide-in-from-bottom-10 fade-in">
          {/* Header */}
          <div className="p-4 bg-emerald-900/20 border-b border-emerald-500/20 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="relative">
                <div className="w-8 h-8 rounded-full bg-emerald-500/20 flex items-center justify-center border border-emerald-400">
                  <Bot size={18} className="text-emerald-400" />
                </div>
                <span className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 rounded-full border-2 border-slate-900"></span>
              </div>
              <div>
                <h3 className="text-sm font-bold text-white">Bubble AI</h3>
                <p className="text-xs text-emerald-400/80">Online • Derja/En</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-white transition-colors">
              <X size={18} />
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                  msg.sender === 'user' 
                    ? 'bg-emerald-600 text-white rounded-tr-none' 
                    : 'bg-slate-800/80 text-slate-200 border border-slate-700 rounded-tl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-slate-800/80 p-3 rounded-2xl rounded-tl-none border border-slate-700 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce delay-100"></span>
                  <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce delay-200"></span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 bg-slate-900/50 border-t border-emerald-500/20">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask me anything... (e.g. Wach rak?)"
                className="w-full bg-slate-800/50 text-white pl-4 pr-10 py-2.5 rounded-xl border border-slate-700 focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 outline-none placeholder:text-slate-500 text-sm transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 text-emerald-500 hover:text-emerald-400 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <Send size={18} />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* FAB Trigger */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg shadow-emerald-500/20 transition-all duration-300 hover:scale-110 active:scale-95 group ${
          isOpen ? 'bg-slate-800 border border-emerald-500/50' : 'bg-emerald-600 hover:bg-emerald-500'
        }`}
      >
        {isOpen ? (
          <X className="text-emerald-400" size={24} />
        ) : (
          <div className="relative">
            <Sparkles className="absolute -top-3 -right-3 text-yellow-300 animate-pulse" size={12} />
            <MessageCircle className="text-white" size={24} />
          </div>
        )}
      </button>
    </div>
  );
};

export default BubbleAssistant;

import React, { useState, useRef, useEffect } from 'react';
import { Terminal as TermIcon } from 'lucide-react';
import { PERSONAL_INFO } from '../constants';

const Terminal: React.FC = () => {
  const [history, setHistory] = useState<string[]>(["Welcome to Samet's Terminal v1.0. Type 'help' for commands."]);
  const [input, setInput] = useState('');
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  const handleCommand = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      const cmd = input.trim().toLowerCase();
      let output = '';

      switch (cmd) {
        case 'help':
          output = "Available commands: about, contact, skills, github, clear";
          break;
        case 'about':
          output = PERSONAL_INFO.bio;
          break;
        case 'contact':
          output = `Email: ${PERSONAL_INFO.email} | Phone: ${PERSONAL_INFO.phone}`;
          break;
        case 'skills':
          output = "Python, NLP, React, TypeScript, Streamlit, Algerian Derja Processing";
          break;
        case 'github':
          window.open(PERSONAL_INFO.github, '_blank');
          output = "Opening GitHub...";
          break;
        case 'clear':
          setHistory([]);
          setInput('');
          return;
        default:
          output = `Command not found: ${cmd}. Try 'help'.`;
      }

      setHistory([...history, `> ${input}`, output]);
      setInput('');
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto mt-20 mb-10 p-4">
      <div className="bg-slate-950 border border-slate-800 rounded-lg overflow-hidden font-mono text-sm shadow-2xl">
        <div className="bg-slate-900 px-4 py-2 flex items-center gap-2 border-b border-slate-800">
          <TermIcon size={14} className="text-slate-400" />
          <span className="text-slate-400">guest@mr-robot:~/portfolio</span>
          <div className="flex gap-1.5 ml-auto">
            <div className="w-3 h-3 rounded-full bg-red-500/20 border border-red-500/50"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500/20 border border-yellow-500/50"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/20 border border-green-500/50"></div>
          </div>
        </div>
        <div className="p-4 h-48 overflow-y-auto text-emerald-500/90 custom-scrollbar">
          {history.map((line, i) => (
            <div key={i} className="mb-1 break-words">{line}</div>
          ))}
          <div className="flex items-center gap-2">
            <span className="text-blue-400">➜</span>
            <span className="text-purple-400">~</span>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleCommand}
              className="bg-transparent border-none outline-none text-emerald-100 flex-1 focus:ring-0"
              autoFocus
            />
          </div>
          <div ref={bottomRef} />
        </div>
      </div>
    </div>
  );
};

